// src/pages/CustomerDashboard.jsx

import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const user = JSON.parse(localStorage.getItem("user") || "{}");

  const [requests, setRequests] = useState([]);
  const [workers, setWorkers] = useState([]);

  const [form, setForm] = useState({
    workType: "",
    labourId: "",
    labourName: "",
    location: "",
    date: ""
  });

  const jobs = [
    "Electrician",
    "Plumber",
    "Painter",
    "Carpenter",
    "Cleaner",
    "Technician",
    "Welder",
    "Driver"
  ];

  useEffect(() => {
    getRequests();
  }, []);

  /* ================= GET REQUESTS ================= */

  const getRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/request/customer/${user.name}`
      );

      setRequests(res.data);

    } catch (err) {
      console.log(err);
    }
  };

  /* ================= SEARCH WORKERS ================= */

  const searchWorkers = async (workType) => {

    if (!workType) return;

    try {

      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter(worker =>
        worker.skills.includes(workType)
      );

      setWorkers(filtered);

    } catch (err) {
      console.log(err);
    }
  };

  /* ================= SEND REQUEST ================= */

  const sendRequest = async () => {

    if (
      !form.workType ||
      !form.labourId ||
      !form.location ||
      !form.date
    ) {
      return alert("Fill all fields");
    }

    try {

      await axios.post(
        "http://localhost:5000/api/request/send",
        {
          customerName: user.name,
          customerId: user._id,
          labourId: form.labourId,
          labourName: form.labourName,
          workType: form.workType,
          location: form.location,
          date: form.date,
          timings: ["9AM - 12PM"],
          status: "Pending"
        }
      );

      alert("Request Sent");

      setForm({
        workType: "",
        labourId: "",
        labourName: "",
        location: "",
        date: ""
      });

      setWorkers([]);

      getRequests();

    } catch (err) {
      console.log(err);
    }
  };

  /* ================= SUBMIT FEEDBACK ================= */

  const submitFeedback = async (id, rating, comment) => {

    if (!rating || !comment) {
      return alert("Fill rating and review");
    }

    try {

      await axios.put(
        `http://localhost:5000/api/request/feedback/${id}`,
        {
          rating: Number(rating),
          comment
        }
      );

      setRequests(prev =>
        prev.map(r =>
          r._id === id
            ? {
                ...r,
                feedback: {
                  rating,
                  comment
                }
              }
            : r
        )
      );

      alert("Feedback Submitted");

    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div style={styles.page}>

      <Navbar />

      <div style={styles.wrapper}>

        {/* ================= LEFT PANEL ================= */}

        <div style={styles.card}>

          <h2 style={styles.title}>
            Hire Worker
          </h2>

          {/* SELECT WORK */}

          <select
            style={styles.input}
            value={form.workType}
            onChange={(e) => {

              setForm({
                ...form,
                workType: e.target.value
              });

              searchWorkers(e.target.value);
            }}
          >
            <option value="">
              Select Work
            </option>

            {jobs.map(job => (
              <option key={job}>
                {job}
              </option>
            ))}
          </select>

          {/* SELECT WORKER */}

          {workers.length > 0 && (

            <select
              style={styles.input}
              value={form.labourId}
              onChange={(e) => {

                const selectedWorker =
                  workers.find(
                    worker => worker._id === e.target.value
                  );

                setForm({
                  ...form,
                  labourId: selectedWorker._id,
                  labourName: selectedWorker.name
                });
              }}
            >
              <option value="">
                Select Worker
              </option>

              {workers.map(worker => (

                <option
                  key={worker._id}
                  value={worker._id}
                >
                  {worker.name} - {worker.city}
                </option>

              ))}
            </select>
          )}

          {/* LOCATION */}

          <input
            style={styles.input}
            placeholder="Enter Location"
            value={form.location}
            onChange={(e) =>
              setForm({
                ...form,
                location: e.target.value
              })
            }
          />

          {/* DATE */}

          <input
            type="date"
            style={styles.input}
            value={form.date}
            onChange={(e) =>
              setForm({
                ...form,
                date: e.target.value
              })
            }
          />

          {/* BUTTON */}

          <button
            style={styles.button}
            onClick={sendRequest}
          >
            Send Request
          </button>

        </div>

        {/* ================= RIGHT PANEL ================= */}

        <div style={styles.card}>

          <h2 style={styles.title}>
            My Requests
          </h2>

          {requests.length === 0 && (
            <p>No Requests Found</p>
          )}

          {requests.map(req => (

            <div
              key={req._id}
              style={styles.requestCard}
            >

              {/* TOP */}

              <div style={styles.row}>

                <b>
                  {req.labourName}
                </b>

                <span
                  style={{
                    ...styles.badge,

                    background:
                      req.status === "Accepted"
                        ? "#14532d"
                        : req.status === "Rejected"
                        ? "#7f1d1d"
                        : "#1f2937"
                  }}
                >
                  {req.status}
                </span>

              </div>

              {/* DETAILS */}

              <p style={styles.text}>
                Work: {req.workType}
              </p>

              <p style={styles.text}>
                Location: {req.location}
              </p>

              <p style={styles.text}>
                Date: {req.date}
              </p>

              {/* ================= STAR RATING ================= */}

              {req.status === "Accepted" && !req.feedback && (

                <div style={styles.ratingBox}>

                  <p style={styles.rateText}>
                    Rate Worker
                  </p>

                  {/* STARS */}

                  <div style={styles.stars}>

                    {[1,2,3,4,5].map(star => (

                      <span
                        key={star}
                        style={{
                          fontSize: "26px",
                          cursor: "pointer",
                          color:
                            (req.tempRating || 0) >= star
                              ? "#facc15"
                              : "#374151"
                        }}
                        onClick={() =>

                          setRequests(prev =>
                            prev.map(r =>
                              r._id === req._id
                                ? {
                                    ...r,
                                    tempRating: star
                                  }
                                : r
                            )
                          )
                        }
                      >
                        ★
                      </span>

                    ))}

                  </div>

                  {/* REVIEW */}

                  <textarea
                    placeholder="Write review..."
                    style={styles.textarea}
                    value={req.tempComment || ""}
                    onChange={(e) =>

                      setRequests(prev =>
                        prev.map(r =>
                          r._id === req._id
                            ? {
                                ...r,
                                tempComment: e.target.value
                              }
                            : r
                        )
                      )
                    }
                  />

                  {/* SUBMIT */}

                  <button
                    style={styles.button}
                    onClick={() =>
                      submitFeedback(
                        req._id,
                        req.tempRating,
                        req.tempComment
                      )
                    }
                  >
                    Submit Rating
                  </button>

                </div>
              )}

              {/* SAVED FEEDBACK */}

              {req.feedback && (

                <div style={styles.saved}>

                  <p style={styles.savedRating}>
                    ⭐ {req.feedback.rating}/5
                  </p>

                  <p style={styles.savedComment}>
                    {req.feedback.comment}
                  </p>

                </div>
              )}

            </div>

          ))}

        </div>

      </div>
    </div>
  );
}

/* ================= STYLES ================= */

const styles = {

  page: {
    background: "#0b0f19",
    minHeight: "100vh",
    color: "white",
    fontFamily: "Arial"
  },

  wrapper: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "20px",
    padding: "20px",
    maxWidth: "1100px",
    margin: "auto"
  },

  card: {
    background: "#111827",
    border: "2px solid #f97316",
    borderRadius: "14px",
    padding: "18px",
    display: "flex",
    flexDirection: "column",
    gap: "12px"
  },

  title: {
    margin: 0,
    marginBottom: "8px",
    fontSize: "24px"
  },

  input: {
    width: "100%",
    padding: "12px",
    borderRadius: "8px",
    border: "1px solid #374151",
    background: "#0f172a",
    color: "white",
    outline: "none",
    boxSizing: "border-box"
  },

  button: {
    width: "100%",
    padding: "12px",
    background: "#f97316",
    border: "none",
    borderRadius: "8px",
    color: "white",
    fontWeight: "bold",
    cursor: "pointer"
  },

  requestCard: {
    border: "1px solid #374151",
    borderRadius: "10px",
    padding: "14px",
    background: "#0f172a",
    display: "flex",
    flexDirection: "column",
    gap: "6px"
  },

  row: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center"
  },

  badge: {
    padding: "5px 10px",
    borderRadius: "6px",
    fontSize: "12px",
    fontWeight: "bold"
  },

  text: {
    margin: 0,
    fontSize: "14px",
    color: "#cbd5e1"
  },

  ratingBox: {
    marginTop: "10px",
    borderTop: "1px solid #374151",
    paddingTop: "10px"
  },

  rateText: {
    marginBottom: "6px",
    color: "#facc15",
    fontWeight: "bold"
  },

  stars: {
    display: "flex",
    gap: "5px",
    marginBottom: "10px"
  },

  textarea: {
    width: "100%",
    height: "70px",
    borderRadius: "8px",
    border: "1px solid #374151",
    background: "#111827",
    color: "white",
    padding: "10px",
    resize: "none",
    marginBottom: "10px",
    boxSizing: "border-box"
  },

  saved: {
    marginTop: "10px",
    background: "#111827",
    padding: "10px",
    borderRadius: "8px",
    border: "1px solid #374151"
  },

  savedRating: {
    margin: 0,
    color: "#facc15",
    fontWeight: "bold"
  },

  savedComment: {
    marginTop: "6px",
    color: "#d1d5db",
    fontSize: "14px"
  }
};
